    {
      "n": 59,
      "column": "left",
      "text": "To dsirdeja Deews/ un\napſkaitahs/ un atmette Iſraëlu\ntohti.\n"
    },
    {
      "n": 60,
      "column": "left",
      "text": "Un pamette to Dsihwokti\neekſch Sihsus/ to Telti/ ko wiꞥſch\nbij par Mahjas-Weetu lizzis\nſtarp teem Zilwekeem.\n"
    },
    {
      "n": 61,
      "column": "left",
      "text": "Un dewe wiꞥſch Spehku\nZeetuma/ un wiꞥſch Sohdibu\nPrettineeka Rohka.\n"
    },
    {
      "n": 62,
      "column": "left",
      "text": "Un nodeewe wiꞥſch Laudis Sohbinam/ un apſkaitahs\nprett tawu eemantojanu Teefu.\n"
    },
    {
      "n": 63,
      "column": "left",
      "text": "Ugguns aprihje wiꞥſch\nJaunektus/ un wiꞥſch Jum-\nprawas ne tappe flawetas.\n"
    },
    {
      "n": 64,
      "column": "left",
      "text": "Wiꞥſch Preesterti kritte\nzaur Sohbinu/un wiꞥſch Atrait-\nnes ne randaja.\n"
    },
    {
      "n": 65,
      "column": "left",
      "text": "Tad usimohdahs tas\nKUNGS/ ta weens/ kas gul-\nlejs/ itt ta weens Warrenajs/\ntas no Wihna klaiga.\n"
    },
    {
      "n": 66,
      "column": "left",
      "text": "Un fitte wiꞥſch Prettinee-\nkus pee Pakkatahm/ un likke\ntohs us muhschigeem Laikeem\nRauna.\n"
    },
    {
      "n": 67,
      "column": "left",
      "text": "Un atmette Jahsepa Dsih-\nwokli/ un ne iswehleja Eewrai-\nma Zilti.\n"
    },
    {
      "n": 68,
      "column": "left",
      "text": "Jo wiꞥſch iswehleja to\nZilti Juha/ Zianas Kalnu/ ko\nwiꞥſch mihleja.\n"
    },
    {
      "n": 69,
      "column": "left",
      "text": "Un ustatſſja tawu fiveh-\ntu Weetu ta patt ta Augsta-\nmus/ ta weenu Seunni/ kas us\nmuhſchtgeem Laikeem darrita.\n"
    },
    {
      "n": 70,
      "column": "left",
      "text": "Un wiꞥſch iswehleja Dah-\n"
    },
    {
      "n": 71,
      "column": "right",
      "text": "No teem fihdameem\nreem likke wiꞥſch to nahkt/\ntabu wiꞥſch Laudis ganni\nun Iſraëlu wiꞥſch eemantoja\nTeefu.\n"
    },
    {
      "n": 72,
      "column": "right",
      "text": "Un wiꞥſch gannija t\nar ſtaidrn Sirdi/ un wali\ntohs ar ſaprattigu Rohku.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Ta LXXIX. Dseesma.\nWeena fuupfama un luhsama Dseefma\nto brecfmigu Iſpohſtſchcanu ta Jerusal\npilsfahta/kur no teem Pagazeem ta D\nKalpoſchang nizzinata : 1. Tee Pre\nnokauti : 2. Un tee Deewabihiigi nesche\nmobziti taptu : 3. Luhsf tapehz/ ka D\nfawu Duſmibu gribbetu pahr teem Ee\nneekeem iogahſt : 6. Bet wiꞥſchneem fa\nGrehkus peedoht : 8. Un schehligi p\ndseht : 9.\nWeena Afawa Dseefma.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "AR Deews! Pagant\ntawa eemantoja\nTeefā nahkuschi/ tee\ntawu twehtu Deewa Nami\nfagahniſchi/ un Jerusalemi\nAkminu-Kohpahm darriſcht.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Tee irr tawu Kalpu\nmirrufchas Meefas par Barr\nteem Putneem appakſch Deb\nfi dewufschi/ tahs Meefas ta\nSwehto teem Semmes Sw\nreem.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Tee irr wiꞥſch Affinis\nkahrt Jerusalemi islehjuſchi\nUhdenf/ un ne weens bija/\naprakfe.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Mehs effam faweem R\nmixeem par Raunu tappufe\npar Apmehdſchann un Sme\nteem/ kas apkahrt mums irr.\n"
    }
  ],
